import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import LockIcon from '@mui/icons-material/Lock';
import response from './response.json';

interface RecentAccessLog {
  time: string;
  user: string;
}

interface LockData {
  lockStatus: string;
  recentAccessLog: RecentAccessLog[];
  authorizedUsersCount: number;
}

export default function Widget() {
  const lockData = response.data as LockData;
  const { lockStatus, recentAccessLog, authorizedUsersCount } = lockData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 380, bgcolor: 'background.paper' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box display="flex" alignItems="center">
            <LockIcon color="primary" sx={{ mr: 1 }} />
            <Typography variant="h6" fontWeight={600}>
              Smart Lock Status
            </Typography>
          </Box>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Current Status
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: lockStatus === 'Locked' ? 'primary.main' : 'error.main' }}>
              {lockStatus}
            </Typography>
          </Box>
          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 0.5 }}>
              Recent Access
            </Typography>
            <Stack spacing={0.5}>
              {recentAccessLog.map((log, index) => (
                <Chip
                  key={index}
                  label={`${log.user} at ${log.time}`}
                  sx={{ fontSize: '11px', px: 1, py: 0.5 }}
                />
              ))}
            </Stack>
          </Box>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Authorized Users
            </Typography>
            <Typography variant="h5" fontWeight={500}>
              {authorizedUsersCount}
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
